// In-memory cache
const iconCache = new Map<string, IconSvgObject>();

export async function loadIcon(iconName: string): Promise<IconSvgObject> {
  if (iconCache.has(iconName)) return iconCache.get(iconName)!;
  const p = paths[iconName];
  if (!p) throw new Error(`Icon not found: ${iconName}`);
  const mod = await import(p);
  const iconData = mod.default || mod;
  iconCache.set(iconName, iconData);
  return iconData;
}

export async function loadIcons(iconNames: string[]): Promise<IconSvgObject[]> {
  return Promise.all(iconNames.map(loadIcon));
}

export function iconExists(iconName: string): boolean {
  return !!paths[iconName];
}

export function clearIconCache(): void {
  iconCache.clear();
}

export function getCacheSize(): number {
  return iconCache.size;
}

// Style-specific aliases for multi-package usage
export const loadIconFreeIcons = loadIcon;
export const loadIconsFreeIcons = loadIcons;

export default { loadIcon, loadIcons, iconExists, clearIconCache, getCacheSize };
